						const adjustedDest = destIndex > sourceIndex ? destIndex - count : destIndex;
						mapTrees.splice(adjustedDest, 0, ...removed);
					} else {
						// For large moves, avoid using `splice` with spread to prevent possible stack overflow.
						const removed = mapTrees.slice(sourceIndex, sourceIndex + count);
						if (destIndex <= sourceIndex) {
